"use strict";(self.webpackChunkweaver_orm_docs=self.webpackChunkweaver_orm_docs||[]).push([[294],{5515(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"category","label":"Getting Started","collapsed":false,"items":[{"type":"link","label":"Introduction","href":"/weaverORM/fr/docs/","docId":"intro","unlisted":false},{"type":"link","label":"Installation","href":"/weaverORM/fr/docs/installation","docId":"installation","unlisted":false},{"type":"link","label":"D\xe9marrage rapide","href":"/weaverORM/fr/docs/quick-start","docId":"quick-start","unlisted":false},{"type":"link","label":"Configuration Symfony","href":"/weaverORM/fr/docs/configuration","docId":"configuration","unlisted":false}],"collapsible":true},{"type":"category","label":"Entity Mapping","items":[{"type":"link","label":"Mapping d\'entit\xe9s","href":"/weaverORM/fr/docs/entity-mapping","docId":"entity-mapping","unlisted":false},{"type":"link","label":"Relations","href":"/weaverORM/fr/docs/relations","docId":"relations","unlisted":false},{"type":"link","label":"Objets int\xe9grables","href":"/weaverORM/fr/docs/embeddable","docId":"embeddable","unlisted":false},{"type":"link","label":"Mapping d\'h\xe9ritage","href":"/weaverORM/fr/docs/inheritance","docId":"inheritance","unlisted":false},{"type":"link","label":"Concerns et traits","href":"/weaverORM/fr/docs/concerns","docId":"concerns","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Entity Workspace","items":[{"type":"link","label":"EntityWorkspace","href":"/weaverORM/fr/docs/workspace","docId":"workspace","unlisted":false},{"type":"link","label":"D\xe9p\xf4ts","href":"/weaverORM/fr/docs/repositories","docId":"repositories","unlisted":false},{"type":"link","label":"Query Builder","href":"/weaverORM/fr/docs/querying","docId":"querying","unlisted":false},{"type":"link","label":"Hooks de Cycle de Vie","href":"/weaverORM/fr/docs/lifecycle","docId":"lifecycle","unlisted":false},{"type":"link","label":"Transactions","href":"/weaverORM/fr/docs/transactions","docId":"transactions","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Schema & Migrations","items":[{"type":"link","label":"Sch\xe9ma et Migrations","href":"/weaverORM/fr/docs/schema-migrations","docId":"schema-migrations","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Advanced","items":[{"type":"link","label":"Collections d\'Entit\xe9s","href":"/weaverORM/fr/docs/collections","docId":"collections","unlisted":false},{"type":"link","label":"Pagination","href":"/weaverORM/fr/docs/pagination","docId":"pagination","unlisted":false},{"type":"link","label":"Tests","href":"/weaverORM/fr/docs/testing","docId":"testing","unlisted":false},{"type":"link","label":"Migration depuis Doctrine","href":"/weaverORM/fr/docs/doctrine-bridge","docId":"doctrine-bridge","unlisted":false},{"type":"link","label":"Support MongoDB","href":"/weaverORM/fr/docs/mongodb","docId":"mongodb","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"PyroSQL","items":[{"type":"link","label":"Overview","href":"/weaverORM/fr/docs/pyrosql/overview","docId":"pyrosql/overview","unlisted":false},{"type":"link","label":"Time Travel","href":"/weaverORM/fr/docs/pyrosql/time-travel","docId":"pyrosql/time-travel","unlisted":false},{"type":"link","label":"Branches","href":"/weaverORM/fr/docs/pyrosql/branches","docId":"pyrosql/branches","unlisted":false},{"type":"link","label":"CDC","href":"/weaverORM/fr/docs/pyrosql/cdc","docId":"pyrosql/cdc","unlisted":false},{"type":"link","label":"Approximate Queries","href":"/weaverORM/fr/docs/pyrosql/approximate","docId":"pyrosql/approximate","unlisted":false},{"type":"link","label":"Vector Search","href":"/weaverORM/fr/docs/pyrosql/vectors","docId":"pyrosql/vectors","unlisted":false},{"type":"link","label":"WASM UDFs","href":"/weaverORM/fr/docs/pyrosql/wasm-udfs","docId":"pyrosql/wasm-udfs","unlisted":false}],"collapsed":true,"collapsible":true}]},"docs":{"collections":{"id":"collections","title":"Collections d\'Entit\xe9s","description":"Weaver\\\\ORM\\\\Collection\\\\EntityCollection is a typed, immutable-by-default collection returned by repositories and query builders. Every method that would mutate the collection returns a new EntityCollection instance, so the original is never modified. This makes collections safe to pass around without defensive copying.","sidebar":"tutorialSidebar"},"concerns":{"id":"concerns","title":"Concerns et traits","description":"Weaver ORM fournit des concerns int\xe9gr\xe9s \u2014 des traits PHP qui ajoutent des comportements courants (timestamps, suppressions douces, g\xe9n\xe9ration UUID) aux entit\xe9s et \xe0 leurs mappers. Ils suivent la m\xeame philosophie de mapping explicite : chaque concern contribue \xe0 la fois la logique PHP c\xf4t\xe9 entit\xe9 et les d\xe9finitions de colonnes c\xf4t\xe9 mapper.","sidebar":"tutorialSidebar"},"configuration":{"id":"configuration","title":"Configuration Symfony","description":"Weaver ORM est configur\xe9 via config/packages/weaver.yaml. Cette page couvre toutes les options disponibles.","sidebar":"tutorialSidebar"},"doctrine-bridge":{"id":"doctrine-bridge","title":"Migration depuis Doctrine","description":"Weaver ORM ships a compatibility bridge that lets you migrate an existing Doctrine ORM codebase incrementally. The bridge exposes the familiar Doctrine EntityManager API as a thin, deprecated wrapper over the Weaver internals so that existing code continues to compile and run while you migrate file by file.","sidebar":"tutorialSidebar"},"embeddable":{"id":"embeddable","title":"Objets int\xe9grables","description":"Un objet int\xe9grable (aussi appel\xe9 objet valeur dans la terminologie DDD) est une classe PHP dont les propri\xe9t\xe9s sont stock\xe9es sous forme de colonnes dans la table de l\'entit\xe9 parente \u2014 pas de jointure, pas de table s\xe9par\xe9e. Weaver g\xe8re le mapping des colonnes et la logique de pr\xe9fixe via un AbstractEmbeddableMapper d\xe9di\xe9.","sidebar":"tutorialSidebar"},"entity-mapping":{"id":"entity-mapping","title":"Mapping d\'entit\xe9s","description":"Weaver ORM s\xe9pare les objets de domaine des m\xe9tadonn\xe9es de persistance en pla\xe7ant toutes les informations de mapping dans une classe mapper d\xe9di\xe9e. Cette page couvre tous les aspects de la configuration des mappers.","sidebar":"tutorialSidebar"},"inheritance":{"id":"inheritance","title":"Mapping d\'h\xe9ritage","description":"Weaver ORM supporte trois sch\xe9mas d\'h\xe9ritage. Choisissez en fonction de la similarit\xe9 des sch\xe9mas de vos sous-classes et de la fr\xe9quence \xe0 laquelle vous avez besoin d\'interroger tous les types dans un seul SELECT.","sidebar":"tutorialSidebar"},"installation":{"id":"installation","title":"Installation","description":"Pr\xe9requis","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"Qu\'est-ce que Weaver ORM ?","description":"Weaver ORM est un mappeur objet-relationnel PHP 8.4+ pour les applications Symfony, construit sur un seul principe : vos objets de domaine ne doivent avoir aucune connaissance de la base de donn\xe9es. Pas d\'annotations sur les classes entit\xe9, pas de g\xe9n\xe9ration de proxy, pas de r\xe9flexion \xe0 l\'ex\xe9cution \u2014 uniquement des objets PHP simples et des classes de mapping explicites qui font le lien entre eux et le SQL.","sidebar":"tutorialSidebar"},"lifecycle":{"id":"lifecycle","title":"Hooks de Cycle de Vie","description":"Weaver ORM provides a set of PHP 8 attributes that let you attach callbacks directly to entity methods. These callbacks are invoked at specific points in the entity\'s persistence lifecycle \u2014 before or after insert, update, delete, and load operations.","sidebar":"tutorialSidebar"},"mongodb":{"id":"mongodb","title":"Support MongoDB","description":"Weaver ORM includes first-class support for MongoDB through a document-oriented abstraction layer. The API mirrors the relational ORM closely, so switching between SQL and MongoDB entities requires minimal mental overhead.","sidebar":"tutorialSidebar"},"pagination":{"id":"pagination","title":"Pagination","description":"Weaver ORM provides three paginator types for different use cases: Page (standard offset pagination), SimplePage (lightweight, no total count), and CursorPage (cursor-based, ideal for infinite scroll and large datasets).","sidebar":"tutorialSidebar"},"pyrosql/approximate":{"id":"pyrosql/approximate","title":"Requ\xeates Approximatives","description":"Approximate Query Processing (AQP) lets PyroSQL answer aggregate questions \u2014 COUNT, SUM, AVG \u2014 by scanning a statistical sample of the data instead of reading every row. The result is returned in milliseconds even on tables with billions of rows, at the cost of a small, bounded error margin.","sidebar":"tutorialSidebar"},"pyrosql/branches":{"id":"pyrosql/branches","title":"Branches","description":"PyroSQL branching works like Git branches, but for data. A branch is a lightweight, copy-on-write snapshot of the entire database. It can be queried and mutated independently of its parent, then either merged back or discarded \u2014 without affecting any other branch.","sidebar":"tutorialSidebar"},"pyrosql/cdc":{"id":"pyrosql/cdc","title":"Capture de Donn\xe9es de Changement","description":"Change Data Capture (CDC) is a technique for observing every INSERT, UPDATE, and DELETE that occurs on a database table, in real time, without polling. PyroSQL exposes a streaming SUBSCRIBE TO CHANGES ON  SQL command that yields rows as DML operations are committed to the WAL (Write-Ahead Log). Weaver ORM wraps this mechanism in CdcSubscriber and hydrates each row into a typed CdcEvent.","sidebar":"tutorialSidebar"},"pyrosql/overview":{"id":"pyrosql/overview","title":"Vue d\'ensemble de PyroSQL","description":"PyroSQL is a custom database engine written in Rust. It speaks the PostgreSQL wire protocol version 3 natively, which means every PostgreSQL-compatible library, driver, and tool connects to it without modification \u2014 including the PDO pgsql driver that Doctrine DBAL uses under the hood.","sidebar":"tutorialSidebar"},"pyrosql/time-travel":{"id":"pyrosql/time-travel","title":"Requ\xeates de Voyage dans le Temps","description":"PyroSQL maintains a complete history of every row that has ever existed in the database. Time travel queries let you read data as it appeared at any previous point in time by appending an AS OF clause to the FROM clause of a SELECT statement. This is useful for audit log replay, point-in-time recovery, compliance reports, and debugging data mutations.","sidebar":"tutorialSidebar"},"pyrosql/vectors":{"id":"pyrosql/vectors","title":"Recherche Vectorielle","description":"Vector similarity search lets you find rows whose stored embedding vectors are closest to a query vector. This is the foundation of semantic search, recommendation systems, and AI-powered retrieval \u2014 where \\"closeness\\" is measured by cosine distance, Euclidean (L2) distance, or dot product, rather than exact string or numeric equality.","sidebar":"tutorialSidebar"},"pyrosql/wasm-udfs":{"id":"pyrosql/wasm-udfs","title":"WASM UDFs","description":"PyroSQL supports WebAssembly User-Defined Functions (WASM UDFs) \u2014 custom SQL functions compiled to the WebAssembly binary format and executed inside the database engine. WASM UDFs run in a sandboxed, deterministic environment with near-native performance and no external network access. Once registered, they are callable from any SQL statement.","sidebar":"tutorialSidebar"},"querying":{"id":"querying","title":"Query Builder","description":"EntityQueryBuilder is Weaver ORM\'s fluent query API. It wraps Doctrine DBAL with full entity awareness: results are automatically hydrated into entity objects, global scopes are applied, and soft-delete filters are managed transparently.","sidebar":"tutorialSidebar"},"quick-start":{"id":"quick-start","title":"D\xe9marrage rapide","description":"Ce guide pr\xe9sente un exemple complet et fonctionnel : d\xe9finir une entit\xe9 User, \xe9crire son mapper et effectuer des op\xe9rations de persistance de base avec EntityWorkspace.","sidebar":"tutorialSidebar"},"relations":{"id":"relations","title":"Relations","description":"Weaver ORM d\xe9finit toutes les m\xe9tadonn\xe9es de relation \xe0 l\'int\xe9rieur de la classe mapper de l\'entit\xe9 via une RelationMap. Il n\'y a pas d\'attributs sur les propri\xe9t\xe9s d\'entit\xe9 et pas de r\xe9flexion \xe0 l\'ex\xe9cution. Les relations sont toujours charg\xe9es explicitement \u2014 Weaver n\'\xe9met jamais de requ\xeates surprises dans votre dos.","sidebar":"tutorialSidebar"},"repositories":{"id":"repositories","title":"D\xe9p\xf4ts","description":"Repositories are the primary way to read entities from the database. Every entity has a corresponding repository that encapsulates all query logic for that entity, keeping controllers and services free of raw SQL or query-builder calls.","sidebar":"tutorialSidebar"},"schema-migrations":{"id":"schema-migrations","title":"Sch\xe9ma et Migrations","description":"Weaver ORM generates SQL DDL directly from your mapper classes. The SchemaGenerator reads every registered mapper, converts it into a Doctrine DBAL Schema object, and can create, update, or drop your database schema through a set of Symfony console commands.","sidebar":"tutorialSidebar"},"testing":{"id":"testing","title":"Tests","description":"Weaver ORM provides a dedicated testing toolkit that makes it straightforward to write fast, reliable tests for code that interacts with the database.","sidebar":"tutorialSidebar"},"transactions":{"id":"transactions","title":"Transactions","description":"Weaver ORM provides TransactionManager, a dedicated service for managing database transactions. It supports simple atomic blocks, manual begin/commit/rollback, nested transactions via savepoints, and optimistic locking.","sidebar":"tutorialSidebar"},"workspace":{"id":"workspace","title":"EntityWorkspace","description":"EntityWorkspace is Weaver ORM\'s central unit-of-work service. It tracks entities across a single request, batches all writes, and flushes them to the database in a single coordinated operation. Think of it as the improved successor to Doctrine\'s EntityManager, redesigned for clarity, worker safety, and explicit intent.","sidebar":"tutorialSidebar"}}}}')}}]);